& { $ErrorActionPreference='Continue'; $root=(Resolve-Path -LiteralPath (Get-Location).Path).Path.TrimEnd('\','/'); $skip='[\\/](\.git|node_modules|dist|build|\.next|\.vite|coverage|tmp|temp|\.vercel|\.wrangler)[\\/]'; $codeExt=@('.html','.css','.js','.mjs','.cjs','.jsx','.ts','.tsx','.json','.md'); $sb=[System.Text.StringBuilder]::new(); $all=Get-ChildItem -LiteralPath $root -Recurse -File -Force | Where-Object { $_.FullName -notmatch $skip } | Sort-Object FullName; $code=$all | Where-Object { $codeExt -contains $_.Extension.ToLowerInvariant() }; [void]$sb.AppendLine('FULL PROJECT AUDIT'); [void]$sb.AppendLine('ROOT: ' + $root); [void]$sb.AppendLine('GENERATED: ' + (Get-Date -Format 'yyyy-MM-dd HH:mm:ss')); [void]$sb.AppendLine(''); [void]$sb.AppendLine('GIT'); try { [void]$sb.AppendLine((git branch --show-current 2>&1 | Out-String).TrimEnd()); [void]$sb.AppendLine((git status --short 2>&1 | Out-String).TrimEnd()); [void]$sb.AppendLine((git log -1 --oneline 2>&1 | Out-String).TrimEnd()) } catch { [void]$sb.AppendLine('GIT ERROR: ' + $_.Exception.Message) }; [void]$sb.AppendLine(''); [void]$sb.AppendLine('CODE'); foreach($f in $code){ $rel=$f.FullName.Substring($root.Length).TrimStart('\','/'); [void]$sb.AppendLine(''); [void]$sb.AppendLine('FILE: ' + $rel); [void]$sb.AppendLine('SIZE: ' + $f.Length + ' bytes'); try { [void]$sb.AppendLine([System.IO.File]::ReadAllText($f.FullName,[System.Text.UTF8Encoding]::new($false))) } catch { [void]$sb.AppendLine('READ ERROR: ' + $_.Exception.Message) } }; [void]$sb.AppendLine(''); [void]$sb.AppendLine('INVENTORY'); [void]$sb.AppendLine('TOTAL FILES: ' + $all.Count); foreach($f in $all){ $rel=$f.FullName.Substring($root.Length).TrimStart('\','/'); [void]$sb.AppendLine($rel + ' | ' + $f.Extension + ' | ' + [Math]::Round($f.Length/1KB,2) + ' KB') }; $result=$sb.ToString(); try { Set-Clipboard -Value $result } catch {}; Write-Host ('copied chars: ' + $result.Length); Write-Host ('files indexed: ' + $all.Count); Write-Host ('code files copied: ' + $code.Count) }
